mapper.select:
SELECT tb.id, tb.batch_code, tb.product_id, bp.name AS product_name, tb.company_id, tb.origin_place, tb.start_date, tb.status, tb.regulation_status, tb.public_remark, tb.created_at FROM trace_batch tb LEFT JOIN base_product bp ON tb.product_id = bp.id
AND tb.company_id = #{companyId}
AND tb.batch_code LIKE CONCAT('%',#{q.batchCode},'%')
AND tb.status = #{q.status}
AND tb.regulation_status = #{q.regulationStatus}
AND bp.name LIKE CONCAT('%',#{q.productName},'%')
ORDER BY tb.id DESC
